"use strict";jQuery.Class("Settings_Recruitment_Transitions_Js",{},{collectTransitions:function(){const t=[];return jQuery("#recruitmentTransitionsContainer .js-transition-checkbox:checked").each(function(){const n=jQuery(this);t.push({from:n.data("from"),to:n.data("to")})}),t},registerRowActions:function(){const t=jQuery("#recruitmentTransitionsContainer");t.on("click",".js-select-row",function(){const n=jQuery(this).data("from");t.find('.js-transition-checkbox[data-from="'+n+'"]').prop("checked",!0)}),t.on("click",".js-clear-row",function(){const n=jQuery(this).data("from");t.find('.js-transition-checkbox[data-from="'+n+'"]').prop("checked",!1)}),t.on("click",".js-select-col",function(){const n=jQuery(this).data("to");t.find('.js-transition-checkbox[data-to="'+n+'"]').prop("checked",!0)})},registerSave:function(){const t=this;jQuery("#recruitmentTransitionsContainer").on("click",".js-save-transitions",function(){const n=t.collectTransitions();app.saveAjax("saveTransitions",{transitions:n}).done(function(t){const n=t&&t.result&&t.result.message?app.vtranslate(t.result.message):app.vtranslate("LBL_SAVE_TRANSITIONS_SUCCESS","Settings:Recruitment");Vtiger_Helper_Js.showPnotify({text:n,type:"success",animation:"show"}),window.location.reload()}).fail(function(){Vtiger_Helper_Js.showPnotify({text:app.vtranslate("LBL_SAVE_TRANSITIONS_FAILED","Settings:Recruitment"),type:"error"})})})},registerEvents:function(){this.registerRowActions(),this.registerSave()}}),jQuery(document).ready(function(){(new Settings_Recruitment_Transitions_Js).registerEvents()});